158	static void fz_init_random_context(fz_context *ctx)
159	{
160		if (!ctx)
161			return;
162	
163		ctx->seed48[0] = 0;
164		ctx->seed48[1] = 0;
165		ctx->seed48[2] = 0;
166		ctx->seed48[3] = 0xe66d;
167		ctx->seed48[4] = 0xdeec;
168		ctx->seed48[5] = 0x5;
169		ctx->seed48[6] = 0xb;
170	
171		fz_srand48(ctx, (uint32_t)time(NULL));
172	}
173	
174	void
175	fz_drop_context(fz_context *ctx)
176	{
177		int free_master = 0;
178		int call_log = 0;
179	
180		if (!ctx)
181			return;
182	
183		if (ctx->error.errcode)
184		{
185			fz_flush_warnings(ctx);
186			fz_warn(ctx, "UNHANDLED EXCEPTION!");
187			fz_report_error(ctx);
188	#ifdef CLUSTER
189			abort();
190	#endif
191		}
192	
193	
194		assert(ctx->master);
195		fz_lock(ctx, FZ_LOCK_ALLOC);
196		ctx->master->context_count--;
197		if (ctx->master->context_count == 0)
198		{
199			call_log = 1;
200			if (ctx->master != ctx)
201				free_master = 1;
202		}
203		fz_unlock(ctx, FZ_LOCK_ALLOC);
204	
205		/* We call the log with ctx intact, apart from the master
206		 * pointer having had the context_count reduced. The
207		 * only possible problem here is if fz_log_activity
208		 * clones the context, but it really shouldn't be doing
209		 * that! */
210		if (call_log)
211			fz_log_activity(ctx, FZ_ACTIVITY_SHUTDOWN, NULL);
212		if (free_master)
213			ctx->alloc.free(ctx->alloc.user, ctx->master);
214	
215		/* Other finalisation calls go here (in reverse order) */
216		fz_drop_document_handler_context(ctx);
217		fz_drop_archive_handler_context(ctx);
218		fz_drop_glyph_cache_context(ctx);
219		fz_drop_store_context(ctx);
220		fz_drop_style_context(ctx);
221		fz_drop_tuning_context(ctx);
222		fz_drop_colorspace_context(ctx);
223		fz_drop_font_context(ctx);
224		fz_drop_hyph_context(ctx);
225	
226		fz_flush_warnings(ctx);
227	
228		assert(ctx->error.top == ctx->error.stack_base);
229	
230		/* Free the context itself */
231		if (ctx->master == ctx && ctx->context_count != 0)
232		{
233			/* Need to delay our freeing until all our children have died. */
234			ctx->master = NULL;
235		}
236		else
237		{
238			ctx->alloc.free(ctx->alloc.user, ctx);
239		}
240	}
