255	fz_context *
256	fz_new_context_imp(const fz_alloc_context *alloc, const fz_locks_context *locks, size_t max_store, const char *version)
257	{
258		fz_context *ctx;
259	
260		if (strcmp(version, FZ_VERSION))
261		{
262			fprintf(stderr, "cannot create context: incompatible header (%s) and library (%s) versions\n", version, FZ_VERSION);
263			return NULL;
264		}
265	
266		if (!alloc)
267			alloc = &fz_alloc_default;
268	
269		if (!locks)
270			locks = &fz_locks_default;
271	
272		ctx = Memento_label(alloc->malloc(alloc->user, sizeof(fz_context)), "fz_context");
273		if (!ctx)
274		{
275			fprintf(stderr, "cannot create context (phase 1)\n");
276			return NULL;
277		}
278		memset(ctx, 0, sizeof *ctx);
279	
280		ctx->user = NULL;
281		ctx->alloc = *alloc;
282		ctx->locks = *locks;
283	
284		/* We are our own master! */
285		ctx->master = ctx;
286		ctx->context_count = 1;
287	
288		ctx->error.print = fz_default_error_callback;
289		ctx->warn.print = fz_default_warning_callback;
290	
291		fz_init_error_context(ctx);
292		fz_init_aa_context(ctx);
293		fz_init_random_context(ctx);
294	
295		/* Now initialise sections that are shared */
296		fz_try(ctx)
297		{
298			fz_new_store_context(ctx, max_store);
299			fz_new_glyph_cache_context(ctx);
300			fz_new_colorspace_context(ctx);
301			fz_new_font_context(ctx);
302			fz_new_hyph_context(ctx);
303			fz_new_document_handler_context(ctx);
304			fz_new_archive_handler_context(ctx);
305			fz_new_style_context(ctx);
306			fz_new_tuning_context(ctx);
307		}
308		fz_catch(ctx)
309		{
310			fz_report_error(ctx);
311			fprintf(stderr, "cannot create context (phase 2)\n");
312			fz_drop_context(ctx);
313			return NULL;
314		}
315		return ctx;
316	}
317	
318	fz_context *
319	fz_clone_context(fz_context *ctx)
320	{
321		fz_context *new_ctx;
322	
323		/* We cannot safely clone the context without having locking/
324		 * unlocking functions. */
325		if (ctx == NULL || (ctx->locks.lock == fz_locks_default.lock && ctx->locks.unlock == fz_locks_default.unlock))
326			return NULL;
327	
328		new_ctx = ctx->alloc.malloc(ctx->alloc.user, sizeof(fz_context));
329		if (!new_ctx)
330			return NULL;
331	
332		fz_lock(ctx, FZ_LOCK_ALLOC);
333		ctx->master->context_count++;
334		fz_unlock(ctx, FZ_LOCK_ALLOC);
335		new_ctx->master = ctx->master;
336	
337		/* First copy old context, including pointers to shared contexts */
338		memcpy(new_ctx, ctx, sizeof (fz_context));
339	
340		/* Reset error context to initial state. */
341		fz_init_error_context(new_ctx);
342	
343		/* Then keep lock checking happy by keeping shared contexts with new context */
344		fz_keep_document_handler_context(new_ctx);
345		fz_keep_archive_handler_context(new_ctx);
346		fz_keep_style_context(new_ctx);
347		fz_keep_tuning_context(new_ctx);
348		fz_keep_font_context(new_ctx);
349		fz_keep_hyph_context(new_ctx);
350		fz_keep_colorspace_context(new_ctx);
351		fz_keep_store_context(new_ctx);
352		fz_keep_glyph_cache(new_ctx);
353	
354		return new_ctx;
355	}
356	
357	void fz_set_user_context(fz_context *ctx, void *user)
358	{
359		if (ctx != NULL)
360			ctx->user = user;
361	}
362	
363	void *fz_user_context(fz_context *ctx)
364	{
365		if (ctx == NULL)
366			return NULL;
367	
368		return ctx->user;
369	}
370	
371	void fz_register_activity_logger(fz_context *ctx, fz_activity_fn *activity, void *opaque)
372	{
373		if (ctx == NULL)
374			return;
375	
376		ctx->activity.activity = activity;
377		ctx->activity.opaque = opaque;
378	}
379	
380	void fz_log_activity(fz_context *ctx, fz_activity_reason reason, void *arg)
381	{
382		if (ctx == NULL || ctx->activity.activity == NULL)
383			return;
384	
385		ctx->activity.activity(ctx, ctx->activity.opaque, reason, arg);
386	}
387	
388	int fz_new_document_id(fz_context *ctx)
389	{
390		int id;
391	
392		fz_lock(ctx, FZ_LOCK_ALLOC);
393		while (ctx->master && ctx->master != ctx)
394			ctx = ctx->master;
395		id = ctx->next_document_id++;
396		fz_unlock(ctx, FZ_LOCK_ALLOC);
397	
398		return id;
399	}
